const stdout = String(items[0]?.json?.stdout ?? items[0]?.json?.data ?? '');
const stripAnsi = (value) => value.replace(/\u001b\[[0-9;]*m/g, '');
const lines = stdout
  .split('\n')
  .map((line) => stripAnsi(line).trim())
  .filter(Boolean);

const benignPatterns = [
  /get \/metrics/i,
  /nenhum evento elegivel para replay/i,
  /no email outbox events eligible for replay/i,
  /executando replay de eventos de webhook pendentes\/falhos/i,
];

const criticalPatterns = [
  /"level":"error"/i,
  /"severity":"error"/i,
  /\b(error|erro|fatal|panic|critical|crit|exception|uncaught)\b/i,
  /\b(falha|falhou|failed|failure)\b/i,
  /\b(timeout|timed out|refused|unavailable)\b/i,
];

const interesting = [];
for (const line of lines) {
  if (benignPatterns.some((pattern) => pattern.test(line))) {
    continue;
  }

  const lower = line.toLowerCase();
  const isStructuredWarn = lower.includes('"level":"warn"') || lower.includes('"severity":"warn"');
  const hasCriticalSignal = criticalPatterns.some((pattern) => pattern.test(line));

  if (!hasCriticalSignal && !isStructuredWarn) {
    continue;
  }

  if (isStructuredWarn && !hasCriticalSignal) {
    continue;
  }

  interesting.push(line);
}

const dedup = [...new Set(interesting)].slice(0, 10);
const hasAlerts = dedup.length > 0;
const signature = JSON.stringify(dedup);
const now = Date.now();
const cooldownMs = 30 * 60 * 1000;
const store = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;

if (!hasAlerts) {
  if (store) {
    delete store.lastAlertSignature;
    delete store.lastAlertSentAt;
  }
  return [];
}

if (store) {
  const lastSignature = String(store.lastAlertSignature ?? '');
  const lastSentAt = Number(store.lastAlertSentAt ?? 0);
  const withinCooldown = lastSignature === signature && lastSentAt > 0 && now - lastSentAt < cooldownMs;
  if (withinCooldown) {
    return [];
  }
  store.lastAlertSignature = signature;
  store.lastAlertSentAt = now;
}

const message = [
  'Alerta FeConect',
  '',
  'Erros recentes nos containers:',
  '',
  ...dedup.map((line) => `- ${line}`),
].join('\n');

return [{ json: { hasAlerts: true, alerts: dedup, message } }];
